        ("मानव फेफड़ों में वायु कोषों (Alveoli) की संख्या लगभग कितनी है?", ["A) 30 लाख", "B) 70 करोड़", "C) 1 करोड़", "D) 5 करोड़"], "B", "UPSC Pre 2015", "मानव फेफड़ों में लगभग 70 करोड़ (700 million) वायु कोष (Alveoli) होते हैं।"),
        ("हीमोग्लोबिन में कौन सी धातु होती है?", ["A) जिंक", "B) लोहा (आयरन)", "C) कॉपर", "D) मैग्नीशियम"], "B", "SSC CGL 2015, RRB NTPC 2016, BPSC 2018", "हीमोग्लोबिन में लोहा (Fe) होता है।"),
        ("दमा (Asthma) किस अंग से संबंधित रोग है?", ["A) हृदय", "B) फेफड़े और श्वास नली", "C) यकृत", "D) गुर्दे"], "B", "SSC MTS 2018, RRB Group D 2019", "दमा (Asthma) श्वसन तंत्र का रोग है।"),
        ("सामान्य व्यक्ति एक मिनट में कितनी बार साँस लेता है?", ["A) 10-12", "B) 16-18", "C) 25-30", "D) 5-8"], "B", "RRB NTPC 2018, SSC CHSL 2019", "एक सामान्य स्वस्थ वयस्क व्यक्ति एक मिनट में 16-18 बार साँस लेता है।"),
        ("श्वासोच्छ्वास के समय डायाफ्राम का क्या होता है?", ["A) ऊपर उठता है", "B) नीचे दबता है (संकुचित)", "C) कोई परिवर्तन नहीं", "D) बाहर निकलता है"], "B", "UPSC Pre 2016", "श्वास लेते समय (Inhalation) डायाफ्राम नीचे की ओर दबता है।"),
        ("शरीर में ऑक्सीजन का परिवहन मुख्यत: किसके द्वारा होता है?", ["A) श्वेत रक्त कोशिकाएँ", "B) हीमोग्लोबिन (लाल रक्त कोशिकाएँ)", "C) प्लाज्मा", "D) प्लेटलेट्स"], "B", "SSC CGL 2016, RRB NTPC 2017", "ऑक्सीजन मुख्यतः लाल रक्त कोशिकाओं (RBC) में उपस्थित हीमोग्लोबिन द्वारा परिवहित होती है।"),
        ("TB (क्षय रोग) किस जीवाणु से होता है?", ["A) विब्रियो कॉलेरी", "B) माइकोबैक्टीरियम ट्यूबरकुलोसिस", "C) क्लोस्ट्रीडियम", "D) स्ट्रेप्टोकॉकस"], "B", "SSC CGL 2014, UPSC Pre 2013, RRB 2016", "TB (Tuberculosis) माइकोबैक्टीरियम ट्यूबरकुलोसिस जीवाणु से होता है।"),
